 40→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, onSwitchToCanvas, promptId = null}) => {
 41→    const [editor] = useLexicalComposerContext();
 42→    const [editorState, setEditorState] = useState(null);
