 51→        e.stopPropagation();
 52→        setIsSending(true)
 53→        try {
 54→            const formdata = new FormData();
 55→            if(title && editorState){
 56→                formdata.append('title', title)
 57→                formdata.append('content', editorState)
 58→            }
 59→            if(promptId){
 60→                formdata.append('prompt_id', promptId);
 61→            }
 62→            const saveData = await saveJournal(session?.access_token, formdata)
 63→
 64→            if(saveData){
 65→                // console.log(saveData)
 66→                queryClient.invalidateQueries({queryKey: ['journals']});
 67→                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
 68→                queryClient.invalidateQueries({queryKey: ['streak', user?.userData?.[0]?.id]});
 69→            }
 70→
 71→            setIsSending(false)
 72→        } catch (error) {
 73→            console.error("Error saving journal:", error);
 74→        }finally {
 75→            setIsSending(false)
